// ═══════════════════════════════════════
// PAINEL GERAL — Resumo de todos os produtos
// ═══════════════════════════════════════

const items = $input.all();
const total = items.length;

if (total === 0) {
  return [{ json: { '📦 Produtos': 'Nenhum produto no pipeline ainda. Execute o Pipeline Completo primeiro!' } }];
}

// Status counts
const statusCounts = {};
items.forEach(i => {
  const s = i.json.pipeline_status || 'desconhecido';
  statusCounts[s] = (statusCounts[s] || 0) + 1;
});

// Categorias
const categorias = {};
items.forEach(i => {
  const c = i.json.category || 'geral';
  categorias[c] = (categorias[c] || 0) + 1;
});

// Médias
const avgPrice = items.reduce((acc, i) => acc + (parseFloat(i.json.price) || 0), 0) / total;
const avgMargin = items.reduce((acc, i) => acc + (parseFloat(i.json.margin) || 0), 0) / total;
const avgTrend = items.reduce((acc, i) => acc + (parseInt(i.json.trend_score) || 0), 0) / total;
const avgViability = items.reduce((acc, i) => acc + (parseInt(i.json.viability_score) || 0), 0) / total;

// Top 3 produtos por viabilidade
const sorted = [...items].sort((a, b) => (b.json.viability_score || 0) - (a.json.viability_score || 0));
const top3 = sorted.slice(0, 3).map((p, i) => 
  `${i+1}. ${p.json.name} (${p.json.viability_score || 0}/100)`
);

const statusEmoji = {
  'novo': '🆕',
  'imagem_processada': '🖼️',
  'descricao_gerada': '📝',
  'pronto': '✅',
  'publicado': '🚀',
  'arquivado': '📦'
};

return [{
  json: {
    '📊 DASHBOARD DE PRODUTOS': '══════════════════════',
    '🔢 Total': `${total} produtos`,
    '': '',
    '📈 PIPELINE STATUS': Object.entries(statusCounts)
      .map(([k,v]) => `${statusEmoji[k] || '❓'} ${k}: ${v}`)
      .join(' · '),
    ' ': '',
    '💰 NÚMEROS': `Preço médio: €${avgPrice.toFixed(2)} | Margem média: ${avgMargin.toFixed(1)}%`,
    '🎯 SCORES': `Tendência: ${avgTrend.toFixed(0)}/100 | Viabilidade: ${avgViability.toFixed(0)}/100`,
    '📂 CATEGORIAS': Object.entries(categorias).map(([k,v]) => `${k} (${v})`).join(' · '),
    '  ': '',
    '🏆 TOP 3 PRODUTOS': top3.join(' | '),
    '   ': '',
    '⏰ Atualizado': new Date().toLocaleString('pt-PT'),
  }
}];

// ═══════════════════════════════════════
// TABELA DETALHADA DE PRODUTOS
// ═══════════════════════════════════════

const items = $input.all();

const statusEmoji = {
  'novo': '🆕',
  'imagem_processada': '🖼️',
  'descricao_gerada': '📝',
  'pronto': '✅',
  'publicado': '🚀',
  'arquivado': '📦'
};

return items.map(item => {
  const p = item.json;
  const data = new Date(p.created_at);
  const tags = p.tags ? (typeof p.tags === 'string' ? JSON.parse(p.tags) : p.tags) : [];

  return {
    json: {
      '📦 Produto': p.name || 'Sem nome',
      '💰 Preço': `€${p.price || 0}`,
      '📊 Margem': `${p.margin || 0}%`,
      '🎯 Viabilidade': `${p.viability_score || 0}/100`,
      '📈 Tendência': `${p.trend_score || 0}/100`,
      '🏪 Fornecedor': p.supplier || '-',
      '📂 Categoria': p.category || '-',
      '🏷️ Tags': tags.slice(0, 3).join(', ') || '-',
      '⚡ Status': `${statusEmoji[p.pipeline_status] || '❓'} ${p.pipeline_status || 'desconhecido'}`,
      '📅 Data': data.toLocaleDateString('pt-PT'),
    }
  };
});
